static void controller_set_safe_idle(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };

    if (controller == 0) {
        return output;
    }

    /* Handle sensor timeout - go to safe all-off state */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller_set_safe_idle(controller);
        output.timed_out = true;
        return output;
    }

    bool previous_inlet_open = controller->inlet_open;
    bool previous_heater_on = controller->heater_on;
    controller_state_t previous_state = controller->state;

    /* Update sensor freshness timestamps */
    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
    } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
    }

    /* Check for stale sensor data - go to safe all-off state */
    uint32_t now_ms = input.now_ms;
    if (controller->has_valid_temperature && (now_ms - controller->last_temperature_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
        controller_set_safe_idle(controller);
        output.timed_out = true;
        return output;
    }
    if (controller->has_valid_level && (now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
        controller_set_safe_idle(controller);
        output.timed_out = true;
        return output;
    }

    /* Stay in safe all-off state until both sensors have been seen validly */
    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        controller_set_safe_idle(controller);
        return output;
    }

    int level = controller->last_level;
    int temperature = controller->last_temperature_c;

    /* Control policy decision */
    bool inlet_open = false;
    bool heater_on = false;

    /* If LEVEL < 55, keep HEATER OFF (low-fill vessel protection) */
    if (level < CONTROLLER_MIN_HEATING_LEVEL) {
        heater_on = false;
    } else if (level < CONTROLLER_FILL_LEVEL_THRESHOLD) {
        /* Low level - fill mode */
        inlet_open = true;
        heater_on = false;
    } else if (level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
        /* High level - close inlet */
        inlet_open = false;
    } else {
        /* 60 <= LEVEL <= 75 - safe region */
        if (temperature < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* Low temperature in safe region - heat */
            inlet_open = false;
            heater_on = true;
        } else if (temperature >= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* High temperature - shut down */
            inlet_open = false;
            heater_on = false;
        } else {
            /* 45 <= TEMP < 47 or 47 <= TEMP <= 48 */
            if (temperature >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
                /* Check if temperature is rising */
                bool is_rising = false;
                if (controller->previous_temperature_c > 0 && controller->last_temperature_ms > 0) {
                    is_rising = (temperature > controller->previous_temperature_c);
                }

                if (is_rising) {
                    /* Temperature rising in upper band - turn heater off early */
                    inlet_open = false;
                    heater_on = false;
                } else {
                    /* Not rising - hold previous safe state */
                    /* Keep the last known safe heater state */
                    if (heater_on) {
                        heater_on = true;  /* Keep heating if was on */
                    } else {
                        heater_on = false;  /* Keep off if was off */
                    }
                    inlet_open = false;
                }
            } else {
                /* 45 <= TEMP < 47 - hold previous safe state */
                inlet_open = false;
                /* Keep previous heater state */
                if (heater_on) {
                    heater_on = true;
                } else {
                    heater_on = false;
                }
            }
        }
    }

    controller->inlet_open = inlet_open;
    controller->heater_on = heater_on;

    /* Update state based on current actuator commands */
    if (inlet_open) {
        controller->state = CONTROLLER_STATE_FILLING;
    } else if (heater_on && level >= CONTROLLER_MIN_HEATING_LEVEL) {
        controller->state = CONTROLLER_STATE_HEATING;
    } else if (!controller->has_valid_temperature || !controller->has_valid_level) {
        controller->state = CONTROLLER_STATE_SAFE_IDLE;
    } else {
        /* In holding state - preserving safe outputs */
        controller->state = CONTROLLER_STATE_HOLDING;
    }

    output.inlet_open = inlet_open;
    output.heater_on = heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_inlet_open != inlet_open) ||
                     (previous_heater_on != heater_on) ||
                     (previous_state != controller->state);

    return output;
}

